import React, { useState } from "react";

const Login = () => {
  const [role, setRole] = useState("labour");

  return (
    <div
      className="d-flex justify-content-center align-items-center"
      style={{
        height: "100vh",
        background: "linear-gradient(135deg,#141e30,#243b55)"
      }}
    >

      <div className="bg-white p-4 rounded shadow" style={{ width: "350px" }}>

        <h3 className="text-center mb-3">Login</h3>

        {/* ROLE SWITCH */}
        <div className="d-flex mb-3">

          <button
            className={`btn w-50 me-1 ${role === "labour" ? "btn-primary" : "btn-outline-primary"}`}
            onClick={() => setRole("labour")}
          >
            Labour
          </button>

          <button
            className={`btn w-50 ${role === "customer" ? "btn-success" : "btn-outline-success"}`}
            onClick={() => setRole("customer")}
          >
            Customer
          </button>

        </div>

        <input className="form-control mb-2" placeholder="Email" />
        <input className="form-control mb-3" placeholder="Password" type="password" />

        <button className="btn btn-dark w-100">
          Login as {role}
        </button>

      </div>

    </div>
  );
};

export default Login;
